#include <stdio.h>
#include <stdlib.h>

int find(int* parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

void unionSet(int* parent, int* rank, int x, int y, int* scores) {
    int rootX = find(parent, x);
    int rootY = find(parent, y);
    if (rootX != rootY) {
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
        if (scores[rootX] < scores[rootY]) {
            scores[rootX] = scores[rootY];
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* scores = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &scores[i]);
        }
        int Q;
        scanf("%d", &Q);
        int* parent = (int*) malloc(N * sizeof(int));
        int* rank = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        while (Q--) {
            int type;
            scanf("%d", &type);
            if (type == 0) {
                int x, y;
                scanf("%d %d", &x, &y);
                x--;
                y--;
                if (find(parent, x) == find(parent, y)) {
                    printf("Invalid query!\n");
                } else {
                    if (scores[x] > scores[y]) {
                        unionSet(parent, rank, y, x, scores);
                    } else if (scores[x] < scores[y]) {
                        unionSet(parent, rank, x, y, scores);
                    }
                }
            } else {
                int x;
                scanf("%d", &x);
                x--;
                printf("%d\n", find(parent, x) + 1);
            }
        }
        free(scores);
        free(parent);
        free(rank);
    }
    return 0;
}

